#include<bits/stdc++.h>
using namespace std;
long long phi(long long n)
{
    long long ans=n;
    for(long long i=2;i*i<=n;i++)
    {
        if(n%i==0)
        {
            ans=ans/i*(i-1);
            while(n%i==0)
            {
                n/=i;
            }
        }
    }
    if(n>1)
    {
        ans=ans/n*(n-1);
    }
    return ans;
}
long long mod;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y>>=1;
    }
    return ans;
}
int main()
{
    long long a,m,sum=0,x=0;
    scanf("%lld%lld",&a,&m);
    mod=m;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    int i;
    long long tmp=phi(m);
    for(i=1;;i++)
    {
        if(!isdigit(ch))
        {
            break;
        }
        x=x*10+(ch-'0');
        sum=(sum*10%tmp+(ch-'0'))%tmp;
        ch=getchar();
    }
    if(i<=9&&x<=m)
    {
        printf("%lld",fastpow(a,x));
        return 0;
    }
    if(__gcd(a,m)==1)
    {
        printf("%lld",fastpow(a,sum));
        return 0;
    }
    printf("%lld",fastpow(a,sum+tmp));
    return 0;
}
